/**
 * Writes public/js/site-config.js from BOOKSTORE_API_BASE (Vercel / CI).
 * Example: BOOKSTORE_API_BASE=https://my-api.onrender.com/api node scripts/inject-site-config.js
 */
const fs = require('fs');
const path = require('path');

const base = (process.env.BOOKSTORE_API_BASE || '').trim();
const outPath = path.join(__dirname, '..', 'public', 'js', 'site-config.js');
const content = `/**
 * Generated by scripts/inject-site-config.js — do not edit by hand.
 */
window.BOOKSTORE_API_BASE = ${JSON.stringify(base)};
`;

fs.writeFileSync(outPath, content, 'utf8');
console.log('Wrote', outPath, base ? `(${base})` : '(empty = same-origin)');
